//! protocol69-embed-agent -- native SkyMesh hidden-state embedding agent.
//!
//! Claims certificate-bearing `runHiddenEmbed` work from the SkyMesh gateway, executes it against a
//! local native qwen fat-station `/hidden-embed` (raw LE u32 tokens in, raw LE f32 [dim] out), and
//! posts a hard-gated `legAck` carrying the base64 LE-f32 embedding projection.
//!
//! Browser-WebGPU agents run TinyLlama generation and CANNOT produce the qwen-896 embeddings the
//! contextual flux-vector DB lives in, so embedding work is executed by THIS native agent.
//!
//! Contract: distributed-inference/PROTOCOL69_HIDDEN_EMBED.md. The claim/ack HTTP shapes, the
//! certificate constant, and the ureq::Agent setup mirror `protocol69-monster-coordinator.rs`.
//! `workKind:"runHiddenEmbed"` is not (yet) a typed `WorkflowWorkKind` variant, so the claimed-work
//! and legAck wire shapes are raw JSON here; the certificate is still the typed antiqueue constant.

use base64::{engine::general_purpose::STANDARD as BASE64_STANDARD, Engine as _};
use distributed_inference::protocol69::{
    build_protocol69_workflow_certificate, validate_protocol69_workflow_certificate,
    Protocol69WorkflowCertificate, PROTOCOL69_LEG_ACK_CONTRACT_ID,
    PROTOCOL69_LEG_ACK_SCHEMA_VERSION,
};
use serde::{Deserialize, Serialize};
use sha2::{Digest, Sha256};
use std::io::Read;
use std::time::Duration;

const DEFAULT_SKYMESH_URL: &str = "http://127.0.0.1:8788";
const DEFAULT_FAT_STATION_URL: &str = "http://127.0.0.1:8090";
const DEFAULT_AGENT_ID: &str = "embed-agent";
const DEFAULT_POLL_MS: u64 = 500;
const WORK_KIND_HIDDEN_EMBED: &str = "runHiddenEmbed";
const PROVENANCE: &str = "protocol69-embed-agent";

#[derive(Debug, Clone, PartialEq, Eq)]
struct Cli {
    skymesh_url: String,
    fat_station_url: String,
    agent_id: String,
    poll_ms: u64,
    once: bool,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize)]
#[serde(rename_all = "camelCase")]
struct SkymeshClaimRequest {
    agent_id: String,
    skills: Vec<String>,
}

/// Claimed `runHiddenEmbed` work. Raw shape (string `workKind`) per the contract; tolerant of extra
/// gateway-supplied fields.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
struct EmbedClaim {
    status: String,
    #[serde(default)]
    work: Option<EmbedWork>,
}

#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
struct EmbedWork {
    workflow_id: String,
    dispatch_id: String,
    leg_id: String,
    cache_key: String,
    key: String,
    tokens: Vec<u32>,
    #[serde(default)]
    model: Option<String>,
    dim: usize,
    certificate: Protocol69WorkflowCertificate,
    #[serde(default)]
    work_kind: Option<String>,
}

/// legAck projection envelope carrying the embedding (matches the contract's
/// `projection:{ key, dim, embedB64 }`).
#[derive(Debug, Clone, PartialEq, Eq, Serialize)]
#[serde(rename_all = "camelCase")]
struct EmbedProjection {
    key: String,
    dim: usize,
    embed_b64: String,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize)]
#[serde(rename_all = "camelCase")]
struct EmbedLegAck {
    schema_version: String,
    contract_id: String,
    certificate: Protocol69WorkflowCertificate,
    workflow_id: String,
    leg_id: String,
    dispatch_id: String,
    cache_key: String,
    work_kind: String,
    executor: String,
    result_hash: String,
    provenance: String,
    projection: EmbedProjection,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize)]
#[serde(rename_all = "camelCase")]
struct SkymeshLegAckEnvelope {
    ack_kind: String,
    leg_ack: EmbedLegAck,
}

#[derive(Debug, Clone, PartialEq, Eq)]
enum AgentStep {
    Idle,
    Completed { key: String, leg_id: String },
}

fn parse_cli() -> Result<Cli, String> {
    let mut cli = Cli {
        skymesh_url: DEFAULT_SKYMESH_URL.to_string(),
        fat_station_url: DEFAULT_FAT_STATION_URL.to_string(),
        agent_id: DEFAULT_AGENT_ID.to_string(),
        poll_ms: DEFAULT_POLL_MS,
        once: false,
    };

    let mut args = std::env::args().skip(1);
    while let Some(arg) = args.next() {
        match arg.as_str() {
            "--skymesh-url" => {
                cli.skymesh_url = args.next().ok_or("--skymesh-url requires a value")?
            }
            "--fat-station-url" => {
                cli.fat_station_url = args.next().ok_or("--fat-station-url requires a value")?
            }
            "--agent-id" => cli.agent_id = args.next().ok_or("--agent-id requires a value")?,
            "--poll-ms" => {
                cli.poll_ms = args
                    .next()
                    .ok_or("--poll-ms requires a value")?
                    .parse()
                    .map_err(|_| "--poll-ms must be a positive integer".to_string())?;
                if cli.poll_ms == 0 {
                    return Err("--poll-ms must be positive".to_string());
                }
            }
            "--once" => cli.once = true,
            "--help" | "-h" => return Err(usage()),
            other => return Err(format!("unknown arg {other}\n{}", usage())),
        }
    }
    Ok(cli)
}

fn usage() -> String {
    "usage: protocol69-embed-agent [--skymesh-url URL] [--fat-station-url URL] [--agent-id ID] [--poll-ms N] [--once]".to_string()
}

fn normalize_base_url(url: &str) -> String {
    url.trim_end_matches('/').to_string()
}

fn claim_embed_work(agent: &ureq::Agent, cli: &Cli) -> Result<EmbedClaim, String> {
    let url = format!(
        "{}/protocol69/work/claim",
        normalize_base_url(&cli.skymesh_url)
    );
    let body = SkymeshClaimRequest {
        agent_id: cli.agent_id.clone(),
        skills: vec![WORK_KIND_HIDDEN_EMBED.to_string()],
    };
    agent
        .post(&url)
        .set("Content-Type", "application/json")
        .send_json(serde_json::to_value(body).map_err(|error| error.to_string())?)
        .map_err(|error| format!("POST {url} failed: {error}"))?
        .into_json::<EmbedClaim>()
        .map_err(|error| format!("decode SkyMesh claim failed: {error}"))
}

/// Encode tokens as raw LE u32 bytes (the `/hidden-embed` request body).
fn tokens_to_le_u32_bytes(tokens: &[u32]) -> Vec<u8> {
    let mut bytes = Vec::with_capacity(tokens.len() * 4);
    for &tok in tokens {
        bytes.extend_from_slice(&tok.to_le_bytes());
    }
    bytes
}

/// POST {fat_station}/hidden-embed and read the raw LE f32 [dim] response. Returns the raw response
/// bytes (already LE f32) alongside the decoded float count for validation.
fn run_hidden_embed(
    agent: &ureq::Agent,
    fat_station_url: &str,
    tokens: &[u32],
) -> Result<Vec<u8>, String> {
    if tokens.is_empty() {
        return Err("runHiddenEmbed: empty token list".to_string());
    }
    let url = format!("{}/hidden-embed", normalize_base_url(fat_station_url));
    let request_body = tokens_to_le_u32_bytes(tokens);
    let response = agent
        .post(&url)
        .set("Content-Type", "application/octet-stream")
        .send_bytes(&request_body)
        .map_err(|error| format!("POST {url} failed: {error}"))?;

    let mut bytes = Vec::new();
    response
        .into_reader()
        .read_to_end(&mut bytes)
        .map_err(|error| format!("read /hidden-embed response failed: {error}"))?;

    if bytes.is_empty() || bytes.len() % 4 != 0 {
        return Err(format!(
            "/hidden-embed returned {} bytes (not a whole LE f32 vector)",
            bytes.len()
        ));
    }
    Ok(bytes)
}

/// Stable result hash of the embedding bytes: `sha256:<hex>` (deterministic, content-addressed).
fn result_hash(embed_bytes: &[u8]) -> String {
    let mut hasher = Sha256::new();
    hasher.update(embed_bytes);
    let digest = hasher.finalize();
    let mut hex = String::with_capacity(7 + digest.len() * 2);
    hex.push_str("sha256:");
    for byte in digest {
        hex.push_str(&format!("{byte:02x}"));
    }
    hex
}

fn ack_embed_leg(agent: &ureq::Agent, skymesh_url: &str, ack: EmbedLegAck) -> Result<(), String> {
    validate_protocol69_workflow_certificate(&ack.certificate)?;
    let url = format!("{}/protocol69/work/ack", normalize_base_url(skymesh_url));
    let body = SkymeshLegAckEnvelope {
        ack_kind: "legAck".to_string(),
        leg_ack: ack,
    };
    agent
        .post(&url)
        .set("Content-Type", "application/json")
        .send_json(serde_json::to_value(body).map_err(|error| error.to_string())?)
        .map_err(|error| format!("POST {url} failed: {error}"))?;
    Ok(())
}

fn handle_work(http: &ureq::Agent, cli: &Cli, work: EmbedWork) -> Result<AgentStep, String> {
    // The certificate on the claimed work MUST equal the constant antiqueue control-plane cert.
    validate_protocol69_workflow_certificate(&work.certificate)?;
    if work.certificate != build_protocol69_workflow_certificate() {
        return Err("claimed work certificate does not match the antiqueue constant".to_string());
    }
    if let Some(kind) = work.work_kind.as_deref() {
        if kind != WORK_KIND_HIDDEN_EMBED {
            return Err(format!("unexpected workKind {kind}, expected runHiddenEmbed"));
        }
    }

    let embed_bytes = run_hidden_embed(http, &cli.fat_station_url, &work.tokens)?;
    let produced_dim = embed_bytes.len() / 4;
    if produced_dim != work.dim {
        return Err(format!(
            "embedding dim mismatch: fat-station produced {produced_dim}, work expects {}",
            work.dim
        ));
    }

    let embed_b64 = BASE64_STANDARD.encode(&embed_bytes);
    let hash = result_hash(&embed_bytes);

    let ack = EmbedLegAck {
        schema_version: PROTOCOL69_LEG_ACK_SCHEMA_VERSION.to_string(),
        contract_id: PROTOCOL69_LEG_ACK_CONTRACT_ID.to_string(),
        certificate: work.certificate,
        workflow_id: work.workflow_id,
        leg_id: work.leg_id.clone(),
        dispatch_id: work.dispatch_id,
        cache_key: work.cache_key,
        work_kind: WORK_KIND_HIDDEN_EMBED.to_string(),
        executor: "nativeEmbed".to_string(),
        result_hash: hash,
        provenance: PROVENANCE.to_string(),
        projection: EmbedProjection {
            key: work.key.clone(),
            dim: work.dim,
            embed_b64,
        },
    };
    ack_embed_leg(http, &cli.skymesh_url, ack)?;
    Ok(AgentStep::Completed {
        key: work.key,
        leg_id: work.leg_id,
    })
}

fn run_once(http: &ureq::Agent, cli: &Cli) -> Result<AgentStep, String> {
    let claim = claim_embed_work(http, cli)?;
    if claim.status == "idle" {
        return Ok(AgentStep::Idle);
    }
    if claim.status != "claimed" {
        return Err(format!("unexpected SkyMesh claim status {}", claim.status));
    }
    let work = claim
        .work
        .ok_or_else(|| "claimed SkyMesh response omitted work".to_string())?;
    handle_work(http, cli, work)
}

fn run(cli: Cli) -> Result<(), String> {
    let http = ureq::AgentBuilder::new()
        .timeout_connect(Duration::from_secs(2))
        // hidden-embed forward passes can run long for big prompts; be generous on read.
        .timeout_read(Duration::from_secs(120))
        .timeout_write(Duration::from_secs(10))
        .build();

    println!(
        "protocol69-embed-agent skymesh={} fat-station={} agent-id={} poll-ms={}",
        normalize_base_url(&cli.skymesh_url),
        normalize_base_url(&cli.fat_station_url),
        cli.agent_id,
        cli.poll_ms
    );

    loop {
        // Per-item errors must NOT crash the loop: log and continue polling.
        match run_once(&http, &cli) {
            Ok(AgentStep::Idle) => {
                if cli.once {
                    println!("protocol69-embed-agent idle");
                    return Ok(());
                }
                std::thread::sleep(Duration::from_millis(cli.poll_ms));
            }
            Ok(AgentStep::Completed { key, leg_id }) => {
                println!("protocol69-embed-agent completed leg {leg_id} for key {key}");
                if cli.once {
                    return Ok(());
                }
            }
            Err(error) => {
                eprintln!("protocol69-embed-agent error: {error}");
                if cli.once {
                    return Err(error);
                }
                std::thread::sleep(Duration::from_millis(cli.poll_ms));
            }
        }
    }
}

fn main() {
    match parse_cli().and_then(run) {
        Ok(()) => {}
        Err(error) => {
            eprintln!("{error}");
            std::process::exit(2);
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::net::TcpListener;
    use std::sync::{Arc, Mutex};
    use std::thread;
    use tiny_http::{Header, Response, Server};

    fn start_json_server<F>(handler: F) -> String
    where
        F: Fn(String, Vec<u8>) -> (Vec<u8>, &'static str) + Send + Sync + 'static,
    {
        let listener = TcpListener::bind("127.0.0.1:0").expect("bind");
        let addr = listener.local_addr().expect("addr");
        let server = Server::from_listener(listener, None).expect("server");
        let handler = Arc::new(handler);
        thread::spawn(move || {
            for mut request in server.incoming_requests().take(8) {
                let mut body = Vec::new();
                let _ = request.as_reader().read_to_end(&mut body);
                let (response_body, content_type) = handler(request.url().to_string(), body);
                let _ = request.respond(
                    Response::from_data(response_body).with_header(
                        Header::from_bytes("Content-Type", content_type).expect("header"),
                    ),
                );
            }
        });
        format!("http://{addr}")
    }

    fn claim_json(dim: usize) -> serde_json::Value {
        serde_json::json!({
            "status": "claimed",
            "work": {
                "workflowId": "wf-embed-1",
                "dispatchId": "wf-embed-1:native-embed",
                "legId": "native-embed",
                "cacheKey": "embed-cachekey-1",
                "key": "ocean",
                "tokens": [1u32, 2u32, 3u32],
                "model": "qwen2.5-0.5b",
                "dim": dim,
                "workKind": "runHiddenEmbed",
                "certificate": build_protocol69_workflow_certificate(),
            }
        })
    }

    #[test]
    fn tokens_encode_little_endian_u32() {
        let bytes = tokens_to_le_u32_bytes(&[1, 256]);
        assert_eq!(bytes, vec![1, 0, 0, 0, 0, 1, 0, 0]);
    }

    #[test]
    fn result_hash_is_stable_and_prefixed() {
        let a = result_hash(&[1, 2, 3, 4]);
        let b = result_hash(&[1, 2, 3, 4]);
        assert_eq!(a, b);
        assert!(a.starts_with("sha256:"));
        assert_ne!(a, result_hash(&[4, 3, 2, 1]));
    }

    #[test]
    fn agent_claims_runs_hidden_embed_and_acks_leg() {
        let dim = 4usize;
        let embedding: Vec<f32> = vec![0.5, -0.25, 1.0, 2.0];
        let mut embed_bytes = Vec::new();
        for f in &embedding {
            embed_bytes.extend_from_slice(&f.to_le_bytes());
        }
        let expected_b64 = BASE64_STANDARD.encode(&embed_bytes);

        let fat_bytes = embed_bytes.clone();
        let fat_station = start_json_server(move |url, body| {
            assert_eq!(url, "/hidden-embed");
            // request body = LE u32 tokens [1,2,3]
            assert_eq!(body, tokens_to_le_u32_bytes(&[1, 2, 3]));
            (fat_bytes.clone(), "application/octet-stream")
        });

        let ack_body = Arc::new(Mutex::new(None::<String>));
        let ack_body_server = Arc::clone(&ack_body);
        let skymesh = start_json_server(move |url, body| {
            if url == "/protocol69/work/claim" {
                return (claim_json(dim).to_string().into_bytes(), "application/json");
            }
            if url == "/protocol69/work/ack" {
                *ack_body_server.lock().expect("lock") =
                    Some(String::from_utf8_lossy(&body).to_string());
                return (
                    serde_json::json!({"status":"accepted"}).to_string().into_bytes(),
                    "application/json",
                );
            }
            (
                serde_json::json!({"status":"idle"}).to_string().into_bytes(),
                "application/json",
            )
        });

        let cli = Cli {
            skymesh_url: skymesh,
            fat_station_url: fat_station,
            agent_id: "embed-agent".to_string(),
            poll_ms: 1,
            once: true,
        };
        let http = ureq::AgentBuilder::new().build();

        let step = run_once(&http, &cli).expect("run once");
        assert_eq!(
            step,
            AgentStep::Completed {
                key: "ocean".to_string(),
                leg_id: "native-embed".to_string(),
            }
        );

        let body = ack_body.lock().expect("lock").clone().expect("ack posted");
        assert!(body.contains("\"ackKind\":\"legAck\""));
        assert!(body.contains("\"workKind\":\"runHiddenEmbed\""));
        assert!(body.contains("\"key\":\"ocean\""));
        assert!(body.contains(&format!("\"embedB64\":\"{expected_b64}\"")));
        assert!(body.contains("\"resultHash\":\"sha256:"));
    }

    #[test]
    fn idle_claim_yields_idle_step() {
        let skymesh = start_json_server(|_url, _body| {
            (
                serde_json::json!({"status":"idle","work":null})
                    .to_string()
                    .into_bytes(),
                "application/json",
            )
        });
        let cli = Cli {
            skymesh_url: skymesh,
            fat_station_url: "http://127.0.0.1:1".to_string(),
            agent_id: "embed-agent".to_string(),
            poll_ms: 1,
            once: true,
        };
        let http = ureq::AgentBuilder::new().build();
        assert_eq!(run_once(&http, &cli).expect("run once"), AgentStep::Idle);
    }
}
